export default {
	data() {
		return {
			mode: false,
		};
	},
	props: {
		
	},
	computed: {
		groupSaleData(){
			return this.$store.state.groupSaleDatas;
		}
	},
	methods: {
		checkboxChange(e) {
			let values = e.detail.value;
			this.shareDatas = values;
			if(values.length < 6){
				for (let x in this.groupSaleData) {
					for (var i = 0, lenI = this.groupSaleData[x].length; i < lenI; ++i) {
						  this.groupSaleData[x][i].checked = false;
						for (var j = 0, lenJ = values.length; j < lenJ; ++j) {
							if (this.groupSaleData[x][i].u_id + '1' == values[j]) {
								this.groupSaleData[x][i].checked = true;
								this.$forceUpdate();
								break;
							}
						}
					}
				}
			}else{
				uni.showToast({
					icon:'none',
					title:'最多只能有五个共享人'
				})
			}
			
		},
		moveHandle() {},
		choose(item) {
			let ids =[];
			for (let x in this.groupSaleData) {
				for (var i = 0, lenI = this.groupSaleData[x].length; i < lenI; ++i) {
					if(this.groupSaleData[x][i].active == true){
						ids.push(this.groupSaleData[x][i].u_id)
					}
				}
			}
			if(ids.length >= 5){
				uni.showToast({
					icon:'none',
					title:'共享人最多不超过5人'
				})
				item.active  = false;
			}else{
				item.active = !item.active;
			}
			this.$forceUpdate();
		},
		close() {
			this.mode = false;
		},
		open() {
			this.mode = true;
		},
		opens(){},
		submit(){
			let sales =[];
			for (let x in this.groupSaleData) {
				for (var i = 0, lenI = this.groupSaleData[x].length; i < lenI; ++i) {
					if(this.groupSaleData[x][i].active == true){
						sales.push(this.groupSaleData[x][i])
					}
				}
			}
			this.$emit('onShare',sales);
		}
	}
};
